B.IA=s(["Neyin do\u011fru neyin yanl\u0131\u015f oldu\u011funu hisseden, kusursuzu hayal eden, yanl\u0131\u015f olan d\xfczeltilene kadar \xe7abalayan bir yap\u0131ya sahibim.","Duygusal, ili\u015fkilerini \xf6nemseyen, sevgiye de\u011fer veren, cana yak\u0131n, yard\u0131msever, kolay ileti\u015fim kurabilen bir yap\u0131ya sahibim.","Ba\u015far\u0131l\u0131 ve etkileyici olmaktan ho\u015flanan, stat\xfcy\xfc \xf6nemseyen, h\u0131rsl\u0131, enerjik ve rekabet\xe7i bir yap\u0131ya sahibim.","Hassas, empati kurmay\u0131 \xf6nemseyen, \xf6zg\xfcnl\xfc\u011fe ve bireyselli\u011fe \xf6nem veren, derinlemesine d\xfc\u015f\xfcnen bir yap\u0131ya sahibim.","Bilgiye ve ara\u015ft\u0131rmaya merakl\u0131, yaln\u0131z kalmaktan rahats\u0131z olmayan, nesnel analiz yapmaya e\u011filimli bir yap\u0131ya sahibim.","G\xfcven ve emniyet i\xe7inde hissetmeyi \xf6nemseyen, tedbirli, sorgulay\u0131c\u0131, B plan\u0131 bulunduran bir yap\u0131ya sahibim.","Ke\u015ffetmeyi ve yeni deneyimleri seven, iyimser, ne\u015feli, d\u0131\u015fa d\xf6n\xfck ve giri\u015fken bir yap\u0131ya sahibim.","Cesur, kararl\u0131, otoriter, g\xfc\xe7l\xfc ve ba\u011f\u0131ms\u0131z olmay\u0131 \xf6nemseyen, m\xfccadeleden ka\xe7\u0131nmayan bir yap\u0131ya sahibim.","Huzuru arayan, sab\u0131rl\u0131, sakin, gerilimden ka\xe7\u0131nan, \xf6ne \xe7\u0131kmay\u0131 tercih etmeyen bir yap\u0131ya sahibim."],t.s)
B.R_=new A.h4(0,"Kendinizi nas\u0131l tan\u0131mlars\u0131n\u0131z?",B.IA)
B.JB=s(["Hayata bak\u0131\u015f a\xe7\u0131m daha \xe7ok esner.","Kendimle vakit ge\xe7irmenin keyfini \xe7\u0131kart\u0131r\u0131m.","Duygulara kar\u015f\u0131 ilgim ve alakam artar.","Ya\u015fam\u0131mda kendimle ilgili rutinlerin say\u0131s\u0131 artar.","Anlatt\u0131\u011f\u0131m konularda daha iddial\u0131 olurum.","Belirsizlikleri kabul etme ihtimalim artar.","\u0130lgilenmem gereken i\u015flere kar\u015f\u0131 oda\u011f\u0131m artar.","Empati yapar, duygular\u0131m\u0131 rahat\xe7a g\xf6steririm.","Fikirlerimi \xe7ekinmeden ifade ederim."],t.s)
B.R2=new A.h4(1,"Mutlu/rahat bir ya\u015famda g\xf6zlemledi\u011finiz de\u011fi\u015fiklikler?",B.JB)
B.IL=s(["Benimle birlikte geli\u015fecek ve geli\u015fimime katk\u0131 sa\u011flayacak bir ili\u015fki beklerim.","Sevildi\u011fim ve sevece\u011fim i\xe7ten bir ba\u011f beklerim.","Takdir g\xf6rd\xfc\u011f\xfcm, \xf6rnek olacak bir ili\u015fki beklerim.","Sayg\u0131n, derinlikli duygusal yak\u0131nl\u0131kta bir ili\u015fki beklerim.","S\u0131n\u0131rlar\u0131na sayg\u0131 duyulan, ufuk a\xe7\u0131c\u0131 bir ili\u015fki beklerim.","Yarg\u0131lanmadan konu\u015fuldu\u011fu, sadakat temelli bir ili\u015fki beklerim.","Enerjik, mizah\u0131 y\xfcksek, konu\u015ftu\u011fumun hemen anla\u015f\u0131ld\u0131\u011f\u0131 bir ili\u015fki beklerim.","Nerede ve nas\u0131l davran\u0131lmas\u0131n\u0131n bilindi\u011fi bir ili\u015fki beklerim.","Oldu\u011fum gibi kabul edilip bask\u0131 olu\u015fturmayan, motive edici bir ili\u015fki beklerim."],t.s)
B.R4=new A.h4(2,"\u0130kili ili\u015fkilerde beklentiniz nelerdir?",B.IL)
B.Iz=s(["Yanl\u0131\u015f veya k\xf6t\xfc biri olmak.","Sevilmeyen veya istenmeyen biri olmak.","Ba\u015fkalar\u0131ndan geri kalmak, g\xf6r\xfclmemek.","\xd6znelli\u011fimin ve de\u011ferimin yok say\u0131lmas\u0131.","Yetersiz ve i\u015fe yaramaz olmak.","Desteksiz ve rehbersiz kalmak.","Yoksunluk ve ac\u0131 duygusunda s\u0131k\u0131\u015f\u0131p kalmak.","Kontrol edilmek ve zarar g\xf6rmek.","Kay\u0131p, \xe7at\u0131\u015fma ve ayr\u0131l\u0131k ya\u015famak."],t.s)
B.R0=new A.h4(3,"Sizi kayg\u0131land\u0131ran durumlar nelerdir?",B.Iz)
B.Jj=s(["Yeteri kadar iyi olmad\u0131\u011f\u0131m\u0131 d\xfc\u015f\xfcnmek benim i\xe7in zordur.","Kendim i\xe7in birinden yard\u0131m istemek benim i\xe7in zordur.","Hedefime ilerlerken yava\u015f hareket etmek benim i\xe7in zordur.","Herkes gibi d\xfc\u015f\xfcnmek, herkes gibi i\u015f yapmak benim i\xe7in zordur.","\u0130natla anlamayan birine a\xe7\u0131klama yapmak benim i\xe7in zordur.","Zihnime s\xf6z ge\xe7irebilmek benim i\xe7in zordur.","Ba\u015flad\u0131\u011f\u0131m i\u015fleri sonuca ula\u015ft\u0131rmak benim i\xe7in zordur.","\u0130\xe7imdeki duygusal y\xf6n\xfc a\xe7\u0131\u011fa vurmak benim i\xe7in zordur.","\u0130\xe7imdekileri \xf6zg\xfcrce d\u0131\u015far\u0131 yans\u0131tmak benim i\xe7in zordur."],t.s)
B.QZ=new A.h4(4,"Yapmakta zorland\u0131\u011f\u0131n\u0131z \u015feyler nelerdir?",B.Jj)
B.JD=s(["\u0130\u015fleri planlama ve mevcut kural/standartlara g\xf6re yapma.","Ki\u015filere ve duygulara odaklanma.","Ba\u015farmak ve en etkili performans\u0131 g\xf6sterebilme.","Hem kendimin hem di\u011fer insanlar\u0131n hislerini anlayabilme.","Her konuya en ince detay\u0131na kadar hakim olabilme.","Herhangi bir konuda emin olabilmek ad\u0131na t\xfcm senaryolar\u0131 d\xfc\u015f\xfcnme.","\u0130lgi ve merak d\xfczeyimi art\u0131ran yenilikleri d\xfc\u015f\xfcnme.","Sorumlu oldu\u011fum ki\u015filere \xf6nc\xfcl\xfck etme.","\xc7evreme uyum ve \xe7evremde dengeyi sa\u011flama."],t.s)
B.R1=new A.h4(5,"Zihninizi en \xe7ok me\u015fgul eden d\xfc\u015f\xfcnceler?",B.JD)
B.Jq=s(["Planl\u0131 \xe7al\u0131\u015fmak, gerekti\u011fi gibi i\u015f yapmak, eksiksiz sonu\xe7land\u0131rmak.","H\u0131zl\u0131 ve s\u0131cak ili\u015fki kurmak, ihtiya\xe7lara duyarl\u0131 olmak.","Sonuca ula\u015fmak, y\u0131lmadan \xe7al\u0131\u015fmak ve ba\u015farma iste\u011fi.","Duygularda fark\u0131ndal\u0131k, empati becerisi ve estetik bak\u0131\u015f a\xe7\u0131s\u0131.","Alan\u0131nda uzmanla\u015fmak, derin \xf6\u011frenme iste\u011fi ve objektif g\xf6zlem.","Sorgulay\u0131c\u0131 olmak, detaylar\u0131 ile \xf6\u011frenmek ve tedbirli olmak.","Her durumda iyimserlik, yeni fikirler \xfcretmek ve co\u015fkulu bir ya\u015fam.","Liderlik yetene\u011fi, g\xfc\xe7l\xfc irade ve h\u0131zl\u0131 harekete ge\xe7mek.","Huzur veren bir ili\u015fki kurmak, uyumlu olmak ve dengeli olmak."],t.s)
B.R5=new A.h4(6,"Ay\u0131r\u0131c\u0131 \xf6zellikleriniz hangileridir?",B.Jq)
B.Ik=s(["Eksik ve hatalar\u0131 g\xf6rerek ele\u015ftirme, m\xfckemmellik aray\u0131\u015f\u0131.","Ge\xe7mi\u015fe ve insanlar\u0131n yapt\u0131klar\u0131na \xe7ok tak\u0131lmak.","Kendinden ve ba\u015far\u0131lar\u0131ndan \xe7ok bahsetme.","Olumsuzlu\u011fu \xfczerine alma ve kendiyle kalma iste\u011fi.","Harekete ge\xe7mede zorlanma, insanlardan uzakla\u015fma.","Kendinden emin olamama, \xf6zg\xfcven konusunda bocalama.","A\u015f\u0131r\u0131 hareketlilik, odaklanamama.","\u0130nsanlar\u0131 dinleyip uygulamama, bildi\u011fini okuma.","\xdc\u015fenge\xe7lik, kendi kabu\u011funa \xe7ekilme."],t.s)
B.R3=new A.h4(7,"\xc7evrenizden en \xe7ok uyar\u0131 ald\u0131\u011f\u0131n\u0131z durumlar?",B.Ik)
